import React, { useState } from 'react';
import { applicationData } from '../../data/applicationData';

function SkillsSection({ data, onUpdate }) {
  const [skillInput, setSkillInput] = useState('');
  const [showSuggestions, setShowSuggestions] = useState(false);

  const LEVELS = ['Beginner', 'Intermediate', 'Advanced', 'Expert'];

  const allSkillsList = [
    ...applicationData.commonKeywords.skills,
    ...applicationData.commonKeywords.technical,
    ...applicationData.commonKeywords.soft
  ];

  const handleSkillInput = (e) => {
    const value = e.target.value;
    setSkillInput(value);
    setShowSuggestions(value.length > 0);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      addSkill(skillInput.trim());
      setSkillInput('');
      setShowSuggestions(false);
    }
  };

  const normalizeSkill = (item) => {
    if (!item) return null;
    if (typeof item === 'string') return { name: item, level: 'Intermediate' };
    if (item.name) return { name: item.name, level: item.level || 'Intermediate' };
    return null;
  };

  const getFlatNames = () => {
    const fromCategory = (arr) => (arr || []).map(s => typeof s === 'string' ? s : s.name);
    return [...fromCategory(data.technical), ...fromCategory(data.soft), ...fromCategory(data.other)];
  };

  const addSkill = (skillName) => {
    if (!skillName) return;
    let category = 'other';
    if (applicationData.commonKeywords.technical.includes(skillName)) category = 'technical';
    else if (applicationData.commonKeywords.soft.includes(skillName)) category = 'soft';

    const flat = getFlatNames();
    if (flat.includes(skillName)) return;

    const newItem = { name: skillName, level: 'Intermediate' };
    const updated = {
      ...data,
      [category]: [...(data[category] || []), newItem]
    };
    onUpdate(updated);
  };

  const removeSkill = (skillName, category) => {
    const updated = {
      ...data,
      [category]: (data[category] || []).filter(skill => (typeof skill === 'string' ? skill : skill.name) !== skillName)
    };
    onUpdate(updated);
  };

  const updateLevel = (skillName, category, level) => {
    const updatedCategory = (data[category] || []).map(item => {
      const itemName = typeof item === 'string' ? item : item.name;
      if (itemName === skillName) {
        return { name: itemName, level };
      }
      return normalizeSkill(item) || item;
    });
    const updated = { ...data, [category]: updatedCategory };
    onUpdate(updated);
  };

  const getFilteredSuggestions = () => {
    const query = skillInput.toLowerCase();
    return allSkillsList.filter(skill => 
      skill.toLowerCase().includes(query) && query.length > 0
    ).slice(0, 5);
  };

  const handleSuggestionClick = (skill) => {
    addSkill(skill);
    setSkillInput('');
    setShowSuggestions(false);
  };

  const renderTag = (item, category) => {
    const normalized = normalizeSkill(item);
    if (!normalized) return null;
    return (
      <div key={normalized.name} className="skill-tag">
        {normalized.name}
        <select 
          className="form-control" 
          style={{ width: 'auto', padding: '2px 8px', fontSize: '12px' }}
          value={normalized.level}
          onChange={(e) => updateLevel(normalized.name, category, e.target.value)}
        >
          {LEVELS.map(l => <option key={l} value={l}>{l}</option>)}
        </select>
        <button 
          onClick={() => removeSkill(normalized.name, category)} 
          aria-label={`Remove ${normalized.name}`}
        >
          ×
        </button>
      </div>
    );
  };

  return (
    <section className="section active">
      <h2>Skills</h2>
      <p className="section-description">List both technical and soft skills relevant to your target role. Set your proficiency level for each skill.</p>
      
      <div className="skills-input-group">
        <input 
          type="text" 
          className="form-control" 
          placeholder="Type a skill and press Enter"
          value={skillInput}
          onChange={handleSkillInput}
          onKeyDown={handleKeyDown}
        />
        {showSuggestions && (
          <div className="skill-suggestions show">
            {getFilteredSuggestions().map(skill => (
              <div 
                key={skill} 
                className="skill-suggestion"
                onClick={() => handleSuggestionClick(skill)}
              >
                {skill}
              </div>
            ))}
          </div>
        )}
      </div>
      
      <div className="skills-container">
        <div className="skill-category">
          <h3>Technical Skills</h3>
          <div className="skills-tags">
            {(data.technical || []).map(item => renderTag(item, 'technical'))}
          </div>
        </div>
        
        <div className="skill-category">
          <h3>Soft Skills</h3>
          <div className="skills-tags">
            {(data.soft || []).map(item => renderTag(item, 'soft'))}
          </div>
        </div>
        
        <div className="skill-category">
          <h3>Other Skills</h3>
          <div className="skills-tags">
            {(data.other || []).map(item => renderTag(item, 'other'))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default SkillsSection;
